class Mover {
  constructor(x, y, m) {
    this.pos = createVector(x, y);
    this.vel = p5.Vector.random2D();
    this.vel.mult(4)
    this.r = sqrt(m) * 2;
    this.acc = createVector(0,0);
    this.mass = m
    this.reduce = -0.8
  }

  edges() {
    if (this.pos.x >= width - this.r) {
      this.pos.x = width - this.r;
      this.vel.x *= this.reduce;
    }
    if (this.pos.x < this.r) {
      this.pos.x = this.r;
      this.vel.x *= this.reduce;
    }
    if (this.pos.y > height - this.r) {
      this.pos.y = height - this.r;
      this.vel.y *= this.reduce;
    }
    if (this.pos.y < this.r) {
      this.pos.y = this.r;
      this.vel.y *= this.reduce;
    }
  }

  drag () {
    const drag = this.vel.copy()
    drag.normalize().mult(-1)
    const speedSq = this.vel.magSq()
    const c = 0.02
    drag.setMag(c * speedSq * this.r)
    this.applyForce(drag)
  }

  friction () {
    const d = height - (this.pos.y + this.r)
    if (d < 1) {

    const friction = this.vel.copy()
    friction.normalize().mult(-1)

    const mu = 0.1
    const normal = this.mass

    friction.setMag(mu * normal)

    this.applyForce(friction)
    }
  }

  applyForce(force) {
    const f = p5.Vector.div(force,this.mass)
    this.acc.add(f)
  }

  update() {
    this.vel.add(this.acc);
    this.pos.add(this.vel);
    this.acc.set(0,0)
  }

  show() {
    noStroke();
    fill(100, 100, 50);
    ellipse(this.pos.x, this.pos.y, this.r * 2);
  }
}

class Attractor {
  constructor(x, y, m) {
    this.pos = createVector(x, y);
    this.mass = m;
    this.r = sqrt(this.mass) * 2;
  }

  getStrength(mover, force) {
    const distanceSq = constrain(force.magSq(), 250, 2500);
    const G = 5;
    const strength = G * (this.mass * mover.mass) / distanceSq;
    return strength
  }

  attract(mover) {
    const force = p5.Vector.sub(this.pos, mover.pos);
    const strength = this.getStrength(mover, force)
    force.setMag(strength)
    mover.applyForce(force);
  }

  show() {
    fill(20, 100, 50);
    ellipse(this.pos.x, this.pos.y, this.r * 2);
  }
}

class Repeller extends Attractor {
  constructor(x,y,m) {
    super(x,y,m)
  }

  repel(mover) {
    const force = p5.Vector.sub(this.pos, mover.pos)
    const strength = this.getStrength(mover, force) * -1
    force.setMag(strength)
    mover.applyForce(force)
  }

  show() {
    fill(50, 100, 50);
    ellipse(this.pos.x, this.pos.y, this.r * 2);
  }
}

