class Froggy{
  constructor(x, y, h, d, o) {
    this.x = x;
    this.y = y;
    this.height = h
    this.max = this.y + o 
    this.min = this.y - o
    this.reverse = false
    this.started = false
    this.delay = d
    this.offset = o
  }

  switch() {
    if (this.y > this.max) {
      this.reverse = true
    } else if (this.y < this.min) {
      this.reverse = false
    }
  }

  oscillate() {
    if (this.reverse) {
      this.y -= 1
    } else {
      this.y += 1
    }
  }

  draw() {
    image(img, this.x, this.y, this.height, this.height)
  }

  update() {
    if (frameCount == this.delay) {
       this.started = true
     }
   if (this.started) {
      this.switch()
      this.oscillate()
      this.draw()
   } else {
     this.draw()
   }
  }
}

