    makeGrid();
  }
  tilePattern(patternWidth);

  // let angle = sin(t) * 20;
  // let angle2 = sin(t);

  translate(-width / 2 + w / 2, -height / 2 + h / 2, 0);
  for (let j = 0; j < rows; j++) {
    for (let i = 0; i < cols; i++) {
      let x = i * w;
      let y = j * h;
      let gid = grid[j][i];
      tile(x, y, w, h, gid);
    }
  }

  t += 0.01;
}

function keyPressed(e) {
  if (e.key == 'f') {
    fullscreen(1);
    setTimeout(() => {
      resizeCanvas(windowWidth, windowHeight);
