  stroke(brushColor);
  line(prevX, prevY, currentX, currentY);
  line(-prevX, -prevY, -currentX, -currentY);
  line(-prevX, prevY, -currentX, currentY);
  line(prevX, -prevY, currentX, -currentY);
  prevX = currentX;
  prevY = currentY;
}

