function calculateFreq() {
  if (rInput.value() == "" || cInput.value() == "") return;
  rMult = resistanceMults[rMultSelect.value()];
  cMult = capacitanceMults[cMultSelect.value()];
  R = rInput.value() * rMult;
  C = cInput.value() * cMult;

  freq = 1 / (2 * log(3) * R * C);

  answer = `${round(freq, 2)} hz`;
}

