class Mover {
  constructor(x, y, m) {
    this.pos = createVector(x, y);
    this.vel = createVector(1,-1)
    this.vel.mult(1)
    this.r = sqrt(m) * 2;
    this.acc = createVector(0,0);
    this.angle = 0
    this.mass = m
    this.reduce = -0.8
  }

  edges() {
    let mult = 3
    if (this.pos.x >= width + mult * this.r) {
      this.pos.x = -this.r;
    }
    if (this.pos.x < -mult * this.r) {
      this.pos.x = width + this.r;

    }
    if (this.pos.y > height + mult *  this.r) {
      this.pos.y = -this.r;
      // this.vel.y *= this.reduce;
    }
    if (this.pos.y < -mult * this.r) {
      this.pos.y = height + mult * this.r
    }
  }

  drag () {
    const drag = this.vel.copy()
    drag.normalize().mult(-1)
    const speedSq = this.vel.magSq()
    const c = 0.06
    drag.setMag(c * speedSq * this.r)
    this.applyForce(drag)
  }

  turn(amount) {
    this.angle += amount
  }

  thrust() {
    const thrust = p5.Vector.fromAngle(this.angle)
    thrust.setMag(4)
    this.applyForce(thrust)
  }

  applyForce(force) {
    const f = p5.Vector.div(force,this.mass)
    this.acc.add(f)
  }

  update() {
    this.vel.add(this.acc)
    this.pos.add(this.vel);
    this.acc.set(0,0)
  }

  show() {
    noStroke();
    fill(100, 100, 50);
    translate(this.pos.x,this.pos.y)
    // rotate(this.angle)
    rotate(this.vel.heading())
    triangle(-this.r, -this.r/2, -this.r, this.r/2, this.r, 0)
  }
}

class Attractor {
  constructor(x, y, m) {
    this.pos = createVector(x, y);
    this.mass = m;
    this.r = sqrt(this.mass) * 2;
  }

  getStrength(mover, force) {
    const distanceSq = constrain(force.magSq(), 250, 2500);
    const G = 5;
    const strength = G * (this.mass * mover.mass) / distanceSq;
    return strength
  }

  attract(mover) {
    const force = p5.Vector.sub(this.pos, mover.pos);
    const strength = this.getStrength(mover, force)
    force.setMag(strength)
    mover.applyForce(force);
  }

  show() {
    fill(20, 100, 50);
    ellipse(this.pos.x, this.pos.y, this.r * 2);
  }
}

class Repeller extends Attractor {
  constructor(x,y,m) {
    super(x,y,m)
  }

  repel(mover) {
    const force = p5.Vector.sub(this.pos, mover.pos)
    const strength = this.getStrength(mover, force) * -1
    force.setMag(strength)
    mover.applyForce(force)
  }

  show() {
    fill(50, 100, 50);
    ellipse(this.pos.x, this.pos.y, this.r * 2);
  }
}

class Wave {
  constructor(amp, period, phase) {
    this.amp = amp;
    this.period = period;
    this.phase = phase;
    this.phaseShift = 0.1;
  }

  update() {
    this.phase += this.phaseShift;
  }

  evaluate(x) {
    let y = sin(this.phase + (TWO_PI * x) / this.period);
    let normalized = map(y, -1, 1, 0, this.amp);

    return normalized;
  }

  setPhaseShift(v) {
    this.phaseShift = v;
  }

  setPeriod(v) {
    this.period = v;
  }
}

