class Particle {
  constructor(x, y) {
    this.pos = createVector(x, y);
    this.vel = createVector(0, 0);
    this.acc = createVector(0, 0);
    this.mass = 1;
    this.locked = false;
  }

  applyForce(force) {
    const f = force.copy();
    f.div(this.mass);
    this.acc.add(f);
  }

  update() {
    if (!this.locked) {
      this.vel.mult(0.99);
      this.vel.add(this.acc);
      this.pos.add(this.vel);
      this.acc.mult(0);
    }
  }

  show() {
    noStroke();
    fill(100, 100, 50);
    ellipse(this.pos.x, this.pos.y, 12);
  }
}

class Spring {
  constructor(k, restLength, a, b) {
    this.k = k;
    this.restLength = restLength;
    this.a = a;
    this.b = b;

  }

  update() {
    const force = p5.Vector.sub(this.b.pos, this.a.pos);
    const x = force.mag() - this.restLength;
    force.normalize()
    force.mult(this.k * x);
    this.a.applyForce(force);
    force.mult(-1)
    this.b.applyForce(force);
  }

  show() {
    strokeWeight(3)
    stroke(220, 100, 80);
    line(this.a.pos.x, this.a.pos.y, this.b.pos.x, this.b.pos.y);
  }
}

